import axios from "axios";

const API = axios.create({
  baseURL: process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api",
});

/**
 * @desc Request Interceptor:  pick token from localStorage put it into header
 */
API.interceptors.request.use((config) => {
  const token = localStorage.getItem("token");
  
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
}, (error) => {
  return Promise.reject(error);
});

/**
 * @desc Response Interceptor: 401 (Unauthorized) handle logout on error
 */
API.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response && error.response.status === 401) {
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      window.location.href = "/";
    }
    return Promise.reject(error);
  }
);

export const loginUser = (formData) => API.post("/auth/login", formData);
export const registerUser = (formData) => API.post("/auth/register", formData);

// Transaction APIs
export const getTransactions = (filters = {}) =>
  API.get("/transactions", { params: filters });

export const getTransaction = (id) => API.get(`/transactions/${id}`);

export const createTransaction = (data) => API.post("/transactions", data);

export const updateTransaction = (id, data) =>
  API.put(`/transactions/${id}`, data);

export const deleteTransaction = (id) => API.delete(`/transactions/${id}`);

export const getTransactionStats = (filters = {}) =>
  API.get("/transactions/stats", { params: filters });

// Budget APIs
export const getBudgets = () => API.get("/budgets");

export const getCurrentMonthBudgets = () => API.get("/budgets/current-month");

export const createBudget = (data) => API.post("/budgets", data);

export const updateBudget = (id, data) => API.put(`/budgets/${id}`, data);

export const deleteBudget = (id) => API.delete(`/budgets/${id}`);

export default API;